const decode = b64 => Buffer.from(b64, 'base64').toString('utf8').trim();
const apiKey = decode($('Get api_key').first().json.payload.data);
const region = decode($('Get region').first().json.payload.data) || 'us';
const client = $('Loop over clients').item.json;
const base = region === 'eu' ? 'https://a.klaviyo.com/api' : 'https://a.klaviyo.com/api';
// Note: Klaviyo's API is the same URL for US and EU as of 2024-10+; region kept for future-proofing.
return [{ json: {
  client_id: client.client_id,
  slug: client.slug,
  currency: client.currency,
  api_key: apiKey,
  region: region,
  api_base: base,
  revision: '2024-10-15'
}}];

const ctx = $('Decode secrets').first().json;
const CLIENT_ID = ctx.client_id;
const CURRENCY = ctx.currency || 'USD';
const INGESTED_AT = new Date().toISOString();
const num = v => (v === null || v === undefined || v === '' ? null : Number(v));
const fmtTs = s => {
  if (!s) return null;
  const d = new Date(s);
  if (isNaN(d.getTime())) return null;
  return d.toISOString().replace('T', ' ').replace(/\.\d+Z$/, '').replace('Z', '');
};

// Klaviyo response shape: { data: [ { id, attributes: {...}, relationships: {...} } ], links: {...} }
const all = [];
for (const it of $input.all()) {
  const j = it.json;
  if (Array.isArray(j.data)) {
    for (const r of j.data) all.push(r);
  } else if (j.id && j.attributes) {
    all.push(j);
  }
}

return all.map(r => {
  const a = r.attributes ?? {};
  return { json: {
    client_id: CLIENT_ID,
    ingested_at: INGESTED_AT,
    campaign_id: String(r.id),
    campaign_name: a.name ?? '',
    channel: 'email',
    status: a.status ?? '',
    send_time: fmtTs(a.send_time),
    list_id: '',
    list_name: '',
    segment_id: '',
    recipients: num(a.recipients_count),
    delivered: num(a.delivered),
    bounces: num(a.bounces),
    opens: num(a.opens),
    unique_opens: num(a.unique_opens),
    open_rate: num(a.open_rate),
    clicks: num(a.clicks),
    unique_clicks: num(a.unique_clicks),
    click_rate: num(a.click_rate),
    unsubscribes: num(a.unsubscribes),
    spam_complaints: num(a.spam_complaints),
    conversions: num(a.conversions),
    revenue: num(a.revenue),
    currency: CURRENCY,
    payload_json: JSON.stringify(r)
  }};
});

